import{_ as i,c as a,o as e,ah as r}from"./chunks/framework.Cnj7lwEt.js";const b=JSON.parse('{"title":"pyrite64","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/游戏开发工具/pyrite64-游戏开发工具.md","filePath":"github汇总/游戏开发工具/pyrite64-游戏开发工具.md"}'),t={name:"github汇总/游戏开发工具/pyrite64-游戏开发工具.md"};function o(n,l,h,s,d,p){return e(),a("div",null,l[0]||(l[0]=[r('<h1 id="pyrite64" tabindex="-1">pyrite64 <a class="header-anchor" href="#pyrite64" aria-label="Permalink to “pyrite64”">​</a></h1><h2 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h2><p>pyrite64</p><h2 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h2><p>HailToDodongo</p><h2 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h2><p>游戏开发工具</p><h2 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h2><p>游戏开发爱好者想要为复古游戏机开发游戏但缺乏合适的工具。</p><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h2><p>N64游戏引擎和可视化编辑器，使用Libdragon和tiny3d创建可在真实N64主机或精确模拟器上运行的3D游戏。支持从Blender导入3D模型（GLTF格式），支持fast64材质。支持HDR加泛光渲染、大纹理渲染（256x256）。运行时引擎处理场景管理、渲染、碰撞检测、音频等核心功能。提供节点图编辑器编写基础控制流程。全局资源管理器自动处理内存清理。Windows平台自动工具链安装。</p><h2 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h2><ul><li>不使用任何任天堂专有SDK或库</li><li>支持Blender模型导入和fast64材质</li><li>HDR加泛光渲染</li><li>大纹理渲染（256x256）</li><li>节点图编辑器</li><li>全局资源管理器</li><li>Windows自动工具链安装</li></ul><h2 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h2><p>README/仓库信息中未明确说明</p><h2 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h2><p><a href="https://github.com/HailToDodongo/pyrite64" target="_blank" rel="noreferrer">https://github.com/HailToDodongo/pyrite64</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h2 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h2><h3 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h3><p>本教程适用于想要使用Pyrite64开发N64游戏的开发者。</p><h3 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h3><ol><li><p><strong>检查操作系统</strong></p><ul><li>执行命令：无</li><li>通过标准：Windows系统（推荐），或Linux/macOS</li></ul></li><li><p><strong>检查Blender是否安装</strong>（用于3D模型导入）</p><ul><li>执行命令：<code>blender -v</code></li><li>通过标准：显示Blender版本号</li></ul></li></ol><h3 id="主路径-windows安装" tabindex="-1">主路径：Windows安装 <a class="header-anchor" href="#主路径-windows安装" aria-label="Permalink to “主路径：Windows安装”">​</a></h3><p><strong>步骤1：克隆项目</strong></p><ul><li>目标：获取项目源码</li><li>位置：本地目录</li><li>命令：<code>git clone https://github.com/HailToDodongo/pyrite64.git</code></li><li>成功标志：项目目录创建成功</li><li>失败处理：检查网络连接 <a href="/网络环境.html">海外网络环境配置 →</a></li></ul><p><strong>步骤2：阅读文档</strong></p><ul><li>目标：了解构建步骤</li><li>位置：浏览器</li><li>操作：访问项目文档 <a href="https://github.com/HailToDodongo/pyrite64/tree/main/docs" target="_blank" rel="noreferrer">https://github.com/HailToDodongo/pyrite64/tree/main/docs</a></li><li>成功标志：理解构建流程</li><li>失败处理：查看FAQ</li></ul><p><strong>步骤3：构建编辑器</strong></p><ul><li>目标：编译编辑器</li><li>位置：项目目录</li><li>操作：按照文档中的构建指南执行</li><li>成功标志：编辑器编译成功</li><li>失败处理：检查依赖是否完整</li></ul><p><strong>步骤4：运行编辑器</strong></p><ul><li>目标：启动编辑器</li><li>位置：项目目录</li><li>操作：运行编译好的编辑器可执行文件</li><li>成功标志：编辑器窗口打开</li><li>失败处理：检查系统兼容性</li></ul><h3 id="备选路径-使用模拟器测试" tabindex="-1">备选路径：使用模拟器测试 <a class="header-anchor" href="#备选路径-使用模拟器测试" aria-label="Permalink to “备选路径：使用模拟器测试”">​</a></h3><p><strong>步骤1：下载精确模拟器</strong></p><ul><li>目标：获取Ares或gopher64模拟器</li><li>位置：浏览器</li><li>操作：访问对应模拟器官网下载</li><li>成功标志：模拟器下载完成</li><li>失败处理：检查网络连接</li></ul><p><strong>步骤2：配置模拟器</strong></p><ul><li>目标：设置模拟器环境</li><li>位置：模拟器设置</li><li>操作：按照模拟器文档配置</li><li>成功标志：模拟器可以运行N64 ROM</li><li>失败处理：查阅模拟器文档</li></ul><h3 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h3><ul><li>编辑器正常启动</li><li>可以创建新项目</li><li>可以导入Blender模型</li></ul><h3 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h3><ol><li><p><strong>工具链安装失败</strong></p><ul><li>可能原因：网络问题或权限问题</li><li>解决步骤：以管理员权限运行，检查网络连接</li></ul></li><li><p><strong>模型导入失败</strong></p><ul><li>可能原因：模型格式不支持</li><li>解决步骤：确保使用GLTF格式，检查fast64材质设置</li></ul></li><li><p><strong>模拟器无法运行游戏</strong></p><ul><li>可能原因：模拟器版本不兼容</li><li>解决步骤：使用Ares v147或更新版本</li></ul></li></ol><h3 id="官方文档" tabindex="-1">官方文档 <a class="header-anchor" href="#官方文档" aria-label="Permalink to “官方文档”">​</a></h3><ul><li><a href="https://github.com/HailToDodongo/pyrite64/tree/main/docs" target="_blank" rel="noreferrer">Pyrite64 Documentation</a> <a href="/网络环境.html">海外网络环境配置 →</a></li><li><a href="https://github.com/HailToDodongo/pyrite64#faq" target="_blank" rel="noreferrer">FAQ</a> <a href="/网络环境.html">海外网络环境配置 →</a></li></ul>',42)]))}const g=i(t,[["render",o]]);export{b as __pageData,g as default};
